import json, os

def idx(f, r): return (7 - r) * 8 + f
def file_of(i): return i % 8
def rank_of(i): return 7 - i // 8
FILE = 'abcdefgh'
R = []

def build_board(cons):
    pat=[]; echo=[]; new=[]; g=0; run=0
    def flush():
        nonlocal run,g
        if run==1:
            g+=1; pat.append('(.)'); echo.append('\\g<%d>'%g); new.append('\\g<%d>'%g)
        elif run>1:
            g+=1; pat.append('(.{%d})'%run); echo.append('\\g<%d>'%g); new.append('\\g<%d>'%g)
        run=0
    for i in range(64):
        c=cons.get(i)
        if c is None:
            run+=1; continue
        flush()
        if c.get('cap'):
            g+=1; pat.append('([pnbrqk])'); echo.append('\\g<%d>'%g); new.append(c['new'])
        else:
            pat.append(c['m']); echo.append(c['echo']); new.append(c['new'])
    flush()
    return ''.join(pat),''.join(echo),''.join(new),g

def move_template(cons, ep_out='-', flags='', castle_req=None, ep_req=None, sf_forbid=None):
    pb,eb,nb,g=build_board(cons)
    C,E,S=g+1,g+2,g+3
    castle_pat='([^;\\n]*%s[^;\\n]*)'%castle_req if castle_req else '([^;\\n]*)'
    ep_pat='(%s)'%ep_req if ep_req else '([^;\\n]*)'
    sf_pat='((?![^;\\n]*[%s])[^;\\n]*)'%sf_forbid if sf_forbid else '([^;\\n]*)'
    pattern='@'+pb+';'+castle_pat+';'+ep_pat+';'+sf_pat
    repl='@'+eb+';\\g<%d>;\\g<%d>;\\g<%d>'%(C,E,S)+'\n>'+nb+';\\g<%d>;%s;%s'%(C,ep_out,flags)
    return [pattern,repl]

DOT='\\.'
def cap_flags(j):
    f=''
    if j==0: f+='D'
    if j==7: f+='E'
    return f
def quiet(i,j,piece,inter=(),flags='',new_piece=None,ep_out='-'):
    np=new_piece or piece
    cons={i:{'m':piece,'echo':piece,'new':'.'}}
    for m in inter: cons[m]={'m':DOT,'echo':'.','new':'.'}
    cons[j]={'m':DOT,'echo':'.','new':np}
    R.append(move_template(cons,ep_out=ep_out,flags=flags))
def capture(i,j,piece,inter=(),flags='',new_piece=None):
    np=new_piece or piece
    cons={i:{'m':piece,'echo':piece,'new':'.'}}
    for m in inter: cons[m]={'m':DOT,'echo':'.','new':'.'}
    cons[j]={'cap':True,'new':np}
    R.append(move_template(cons,flags=flags+cap_flags(j)))

