    return out
def geom(consmap):
    s=''; prev=0
    for i in sorted(consmap):
        gap=i-prev
        if gap==1: s+='.'
        elif gap>1: s+='.{%d}'%gap
        s+=consmap[i]; prev=i+1
    return s

